+) -> Option<&'static JsonlLogger> {
+    if !jsonl_enabled() {
+        return None;
+    }
+    Some(
+        cell.get_or_init(|| {
+            make_demo_logger(default_run_id, extra_context, JsonlSink::Stderr, None)
+        }),
